const assert = require('assert');
const LifecycleManager = require('../../../src/core/LifecycleManager');
const DiContainer = require('../../../src/core/DiContainer');

describe('LifecycleManager (Functional)', () => {
  before(() => DiContainer.reset());

  it('should fully prepare a service with injected dependencies', () => {
    class Logger {
      log(msg) {
        return `LOG: ${msg}`;
      }
    }

    class App {
      logger;
      setConfig(cfg) {
        this.cfg = cfg;
      }

      run() {
        return this.logger.log(this.cfg.env);
      }
    }

    DiContainer.register('Logger', Logger);
    DiContainer.set('__inject:logger', DiContainer.resolve('Logger'));
    DiContainer.set('__injectMethod:setConfig', { env: 'prod' });

    DiContainer.register('App', App);
    const app = LifecycleManager.create(App, 'App');

    assert.strictEqual(app.run(), 'LOG: prod');
  });
});